import { Ionicons } from "@expo/vector-icons";
import React, { useEffect, useMemo, useState } from "react";
import {
  RefreshControl,
  SectionList,
  StyleSheet,
  Text,
  View,
} from "react-native";
import { useAuth } from "../context/AuthContext";
import { useTheme } from "../context/ThemeContext";
import { ThemeColors } from "../utils/Color";
import { DocumentSection, groupByPerson } from "../utils/documents";
import { NavigationProp, showToast } from "../utils/Utils";
import type { RowPosition } from "./DocumentRow";
import FloatingButton from "./FAB";
import { DocumentListSkeleton } from "./Skeleton";

type IconName = React.ComponentProps<typeof Ionicons>["name"];

type PersonDocument = { id: string; personId: string; personName: string };

/**
 * Re-fetches on every focus so a save on the add/edit screen is reflected the
 * moment we navigate back. The whole family shares one vault, so nothing is
 * filtered out here — the list is grouped by person instead.
 */
export const useDocumentList = <T extends PersonDocument>(
  fetcher: () => Promise<T[]>,
  navigation: NavigationProp,
  errorTitle: string
) => {
  const [documents, setDocuments] = useState<T[]>([]);
  const [isRefreshing, setIsRefreshing] = useState(false);
  const [hasLoaded, setHasLoaded] = useState(false);
  const { user } = useAuth();

  const load = () => {
    fetcher()
      .then((data) => setDocuments(data ?? []))
      .catch((error) => {
        console.log(error);
        showToast(
          "error",
          errorTitle,
          "Check your connection and pull down to retry.",
          "bottom"
        );
      })
      .finally(() => {
        setIsRefreshing(false);
        setHasLoaded(true);
      });
  };

  useEffect(() => navigation.addListener("focus", load), [navigation]);

  const onRefresh = () => {
    setIsRefreshing(true);
    load();
  };

  const sections = useMemo(
    () => groupByPerson(documents, user),
    [documents, user]
  );

  return { sections, isRefreshing, hasLoaded, onRefresh };
};

type IDocumentList<T> = {
  sections: DocumentSection<T>[];
  isRefreshing: boolean;
  hasLoaded: boolean;
  onRefresh: () => void;
  onAdd: () => void;
  addLabel: string;
  /** Singular noun for the count line, e.g. "document". */
  noun: string;
  emptyIcon: IconName;
  emptyTitle: string;
  emptyBody: string;
  renderItem: (item: T, position: RowPosition) => React.ReactElement;
};

const DocumentList = <T extends PersonDocument>(props: IDocumentList<T>) => {
  const { sections, hasLoaded, noun } = props;
  const { colors } = useTheme();
  const styles = useMemo(() => createStyles(colors), [colors]);

  const renderSectionHeader = (section: DocumentSection<T>) => (
    <View style={styles.sectionHeader}>
      <Text style={styles.sectionTitle} numberOfLines={1}>
        {section.title}
      </Text>
      <Text style={styles.sectionCount}>
        {section.data.length} {section.data.length === 1 ? noun : `${noun}s`}
      </Text>
    </View>
  );

  const renderEmpty = () => {
    // Never show "nothing here" before the first fetch has actually resolved.
    if (!hasLoaded) {
      return null;
    }
    return (
      <View style={styles.empty}>
        <Ionicons name={props.emptyIcon} size={44} color={colors.textMuted} />
        <Text style={styles.emptyTitle}>{props.emptyTitle}</Text>
        <Text style={styles.emptyBody}>{props.emptyBody}</Text>
      </View>
    );
  };

  // Only the very first fetch gets a skeleton. Re-fetching on focus keeps the
  // list on screen rather than flashing placeholders over data we already have.
  if (!hasLoaded) {
    return (
      <View style={styles.container}>
        <View style={styles.listContent}>
          <DocumentListSkeleton />
        </View>
      </View>
    );
  }

  return (
    <View style={styles.container}>
      <SectionList
        contentContainerStyle={styles.listContent}
        sections={sections}
        keyExtractor={(item, index) => item.id ?? String(index)}
        ListEmptyComponent={renderEmpty}
        renderSectionHeader={({ section }) =>
          renderSectionHeader(section as DocumentSection<T>)
        }
        stickySectionHeadersEnabled={false}
        refreshControl={
          <RefreshControl
            refreshing={props.isRefreshing}
            onRefresh={props.onRefresh}
            tintColor={colors.textMuted}
          />
        }
        renderItem={({ item, index, section }) =>
          props.renderItem(item, {
            isFirst: index === 0,
            isLast: index === section.data.length - 1,
          })
        }
      />
      <FloatingButton accessibilityLabel={props.addLabel} onPress={props.onAdd} />
    </View>
  );
};

const createStyles = (colors: ThemeColors) =>
  StyleSheet.create({
    container: {
      flex: 1,
      backgroundColor: colors.background,
    },
    listContent: {
      paddingTop: 16,
      paddingBottom: 90,
      flexGrow: 1,
    },
    sectionHeader: {
      flexDirection: "row",
      alignItems: "baseline",
      justifyContent: "space-between",
      marginHorizontal: 20,
      marginBottom: 10,
    },
    sectionTitle: {
      flex: 1,
      fontSize: 13,
      fontWeight: "700",
      textTransform: "uppercase",
      letterSpacing: 0.7,
      color: colors.textMuted,
      marginRight: 12,
    },
    sectionCount: {
      fontSize: 12,
      color: colors.textMuted,
      fontVariant: ["tabular-nums"],
    },
    empty: {
      flex: 1,
      alignItems: "center",
      justifyContent: "center",
      paddingHorizontal: 40,
      paddingBottom: 60,
    },
    emptyTitle: {
      fontSize: 17,
      fontWeight: "600",
      color: colors.text,
      marginTop: 14,
    },
    emptyBody: {
      fontSize: 14,
      color: colors.textMuted,
      textAlign: "center",
      marginTop: 6,
      lineHeight: 20,
    },
  });

export default DocumentList;
